	}

	/* graph node staleness — semantic mapping:
	   stale = warning (tier-fast amber/gold), missing = error (status-blocked red),
	   fresh = success (status-closed green). Light/dark resolved via existing CSS vars. */
	.node-stale {
		fill: var(--tier-fast-border);
		stroke: var(--tier-fast-text);
	}
	.node-missing {
		fill: var(--status-blocked-border);
		stroke: var(--status-blocked-text);
	}
	.node-fresh {
		fill: var(--status-closed-border);
		stroke: var(--status-closed-text);
	}
}

input.old_string:
function nodeColorClass(staleness?: string): string {
	if (staleness === 'stale')
		return 'fill-amber-400 stroke-amber-600 dark:fill-amber-500 dark:stroke-amber-400'
	if (staleness === 'missing')
		return 'fill-red-400 stroke-red-600 dark:fill-red-500 dark:stroke-red-400'
	// fresh (default)
	return 'fill-green-400 stroke-green-600 dark:fill-green-500 dark:stroke-green-400'
}

input.new_string:
function nodeColorClass(staleness?: string): string {
	if (staleness === 'stale') return 'node-stale'
	if (staleness === 'missing') return 'node-missing'
	// fresh (default)
	return 'node-fresh'
}

